import React, { useState, useEffect, useRef } from 'react';
import { Database, Table, Maximize, ZoomIn, ZoomOut } from 'lucide-react';
import { Dimension, ModelConfig } from '../types';

interface NodePosition {
  x: number;
  y: number;
}

interface ModelDiagramProps {
  dimensions: Dimension[];
  modelConfig: ModelConfig;
  activeId: string;
  onNodeSelect: (id: string) => void;
}

const ModelDiagram: React.FC<ModelDiagramProps> = ({ dimensions, modelConfig, activeId, onNodeSelect }) => {
  const [scale, setScale] = useState(0.8); // Start slightly smaller to fit side panel
  const containerRef = useRef<HTMLDivElement>(null);

  // Calculate layout
  const [nodePositions, setNodePositions] = useState<Record<string, NodePosition>>({});
  // Adjust center based on container size assumption, or just use relative SVG coords
  const centerX = 400;
  const centerY = 300;
  const radius = 180;

  useEffect(() => {
    const positions: Record<string, NodePosition> = {};
    // Center Fact Table
    positions['general'] = { x: centerX, y: centerY }; // 'general' maps to Fact Table node

    // Orbit Dimensions
    const totalDims = dimensions.length;
    dimensions.forEach((dim, index) => {
      const angle = (index / totalDims) * 2 * Math.PI - (Math.PI / 2); // Start from top
      positions[dim.id] = {
        x: centerX + radius * Math.cos(angle),
        y: centerY + radius * Math.sin(angle)
      };
    });
    setNodePositions(positions);
  }, [dimensions]);

  const handleZoom = (delta: number) => {
    setScale(prev => Math.min(Math.max(0.4, prev + delta), 2));
  };

  const renderConnection = (dimId: string) => {
    const start = nodePositions['general'];
    const end = nodePositions[dimId];
    if (!start || !end) return null;

    const isActive = activeId === dimId;

    return (
      <g key={dimId}>
        <path
          d={`M ${start.x} ${start.y} L ${end.x} ${end.y}`}
          stroke="white"
          strokeWidth="6"
          fill="none"
        />
        <path
          d={`M ${start.x} ${start.y} L ${end.x} ${end.y}`}
          stroke={isActive ? '#2563EB' : '#CBD5E1'}
          strokeWidth={isActive ? '2' : '1.5'}
          strokeDasharray={isActive ? '0' : '5,5'}
          fill="none"
          className="transition-all duration-300"
        />
      </g>
    );
  };

  return (
    <div className="h-full w-full bg-slate-50 relative overflow-hidden group" ref={containerRef}>
        {/* Toolbar */}
        <div className="absolute top-4 left-4 z-10 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
            <div className="bg-white p-1 rounded-md shadow border border-gray-200 flex flex-col gap-1">
                <button onClick={() => handleZoom(0.1)} className="p-1.5 hover:bg-gray-100 rounded text-gray-600"><ZoomIn className="w-3 h-3"/></button>
                <button onClick={() => handleZoom(-0.1)} className="p-1.5 hover:bg-gray-100 rounded text-gray-600"><ZoomOut className="w-3 h-3"/></button>
                <button onClick={() => setScale(0.8)} className="p-1.5 hover:bg-gray-100 rounded text-gray-600"><Maximize className="w-3 h-3"/></button>
            </div>
        </div>

        {/* Legend */}
        <div className="absolute bottom-4 right-4 z-10 bg-white/80 backdrop-blur p-3 rounded-lg shadow-sm border border-gray-200 pointer-events-none">
            <div className="space-y-1.5">
                <div className="flex items-center gap-2">
                    <div className="w-2.5 h-2.5 rounded-full bg-blue-600"></div>
                    <span className="text-[10px] text-gray-600 font-medium">Fact Table</span>
                </div>
                <div className="flex items-center gap-2">
                    <div className="w-2.5 h-2.5 rounded-full bg-white border-2 border-green-500"></div>
                    <span className="text-[10px] text-gray-600 font-medium">Dimension</span>
                </div>
            </div>
        </div>

        {/* Graph Area */}
        <div 
            className="w-full h-full flex items-center justify-center transition-transform duration-200 ease-out origin-center"
            style={{ transform: `scale(${scale})` }}
        >
             <div className="relative w-[800px] h-[600px]">
                <svg className="absolute inset-0 w-full h-full pointer-events-none overflow-visible">
                    {dimensions.map(dim => renderConnection(dim.id))}
                </svg>

                {/* Fact Node */}
                {nodePositions['general'] && (
                    <div 
                        onClick={() => onNodeSelect('general')}
                        className={`absolute w-36 transform -translate-x-1/2 -translate-y-1/2 bg-blue-600 text-white rounded-lg shadow-lg cursor-pointer transition-all duration-300 z-20 hover:scale-105
                        ${activeId === 'general' ? 'ring-4 ring-blue-200 scale-110 shadow-xl' : ''}`}
                        style={{ left: nodePositions['general'].x, top: nodePositions['general'].y }}
                    >
                        <div className="p-3 text-center">
                            <Database className="w-5 h-5 mx-auto mb-1 opacity-90" />
                            <div className="font-bold text-xs truncate px-1">{modelConfig.factTable}</div>
                            <div className="text-[9px] opacity-80 mt-0.5">Central Fact</div>
                        </div>
                    </div>
                )}

                {/* Dimension Nodes */}
                {dimensions.map(dim => {
                    const pos = nodePositions[dim.id];
                    if (!pos) return null;
                    const isSelected = activeId === dim.id;

                    return (
                        <div 
                            key={dim.id}
                            onClick={() => onNodeSelect(dim.id)}
                            className={`absolute w-28 transform -translate-x-1/2 -translate-y-1/2 bg-white rounded-lg border-2 cursor-pointer transition-all duration-300 z-10 hover:shadow-md hover:border-blue-400
                            ${isSelected ? 'border-green-500 shadow-lg scale-110 z-20' : 'border-gray-200'}`}
                            style={{ left: pos.x, top: pos.y }}
                        >
                             <div className="p-2">
                                <div className="flex items-center gap-1.5 mb-1">
                                    <div className={`p-0.5 rounded ${isSelected ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-500'}`}>
                                        <Table className="w-3 h-3" />
                                    </div>
                                    <span className="text-[10px] font-bold text-gray-700 truncate">{dim.code}</span>
                                </div>
                                <div className="text-[9px] text-gray-400 font-mono truncate border-t border-gray-100 pt-1">
                                    {dim.binding}
                                </div>
                             </div>
                        </div>
                    );
                })}
             </div>
        </div>
    </div>
  );
};

export default ModelDiagram;

