                        ${selectedNode === 'fact' ? 'ring-4 ring-blue-200 scale-105' : ''}`}
                        style={{ left: nodePositions['fact'].x, top: nodePositions['fact'].y }}
                    >
                        <div className="p-3 text-center">
                            <Database className="w-6 h-6 mx-auto mb-1 opacity-90" />
