                                </div>
                             </div>
                        </div>
                    );
                })}

             </div>
        </div>
      </div>

      {/* Right Detail Panel */}
      <div className="w-[350px] bg-white z-20 flex flex-col h-full overflow-hidden">
        {selectedNode ? (
            selectedNode === 'fact' ? (
                // Fact Table Details
