import React, { useState } from 'react';
import { LayoutGrid, ShieldCheck, FileCode, Database, Box, ChevronLeft, ChevronRight, Search, Scale } from 'lucide-react';
import { Tab } from '../types.ts';

interface SidebarProps {
  activeTab: Tab;
  setActiveTab: (tab: Tab) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab }) => {
  const [isCollapsed, setIsCollapsed] = useState(false);

  const menuItems = [
    { id: 'structure', label: '模型定义', icon: LayoutGrid },
    { id: 'strategies', label: '维度策略', icon: ShieldCheck },
    { id: 'validations', label: '校验规则', icon: Scale },
    { id: 'scripts', label: '脚本公式', icon: FileCode },
    { id: 'query', label: '数据探索', icon: Search },
  ];

  return (
    <div className={`bg-slate-900 border-r border-slate-800 h-screen flex flex-col justify-between transition-all duration-300 ease-in-out z-20 shadow-xl ${isCollapsed ? 'w-16' : 'w-56'}`}>
      <div>
        <div className={`h-14 flex items-center border-b border-slate-800 ${isCollapsed ? 'justify-center' : 'px-6'}`}>
          <Box className="w-6 h-6 text-blue-400 shrink-0" />
          {!isCollapsed && <span className="ml-3 font-bold text-lg text-white whitespace-nowrap">DeepCube</span>}
        </div>

        <nav className="mt-4 flex flex-col gap-1 px-2">
          {menuItems.map((item) => {
            const isActive = activeTab === item.id;
            return (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id as Tab)}
                className={`flex items-center p-2.5 rounded transition-all duration-200 group relative ${isActive ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'} ${isCollapsed ? 'justify-center' : ''}`}
              >
                <item.icon className={`w-4 h-4 shrink-0 ${isActive ? 'text-white' : 'text-slate-400 group-hover:text-white'}`} />
                {!isCollapsed && <span className="ml-3 text-sm font-medium whitespace-nowrap">{item.label}</span>}
                {isCollapsed && (
                  <div className="absolute left-full ml-2 px-2 py-1 bg-slate-800 text-white text-[10px] rounded opacity-0 group-hover:opacity-100 pointer-events-none whitespace-nowrap z-50">
                    {item.label}
                  </div>
                )}
              </button>
            );
          })}
        </nav>
      </div>

      <div className="pb-4">
        <button onClick={() => setIsCollapsed(!isCollapsed)} className="w-full flex items-center justify-center p-2 text-slate-500 hover:text-white transition-colors">
          {isCollapsed ? <ChevronRight className="w-4 h-4" /> : <ChevronLeft className="w-4 h-4" />}
        </button>
        <div className={`px-4 mt-2 ${isCollapsed ? 'flex justify-center' : ''}`}>
          <div className="flex items-center text-slate-500 bg-slate-800/50 p-2 rounded">
            <Database className="w-4 h-4 shrink-0 text-green-400" />
            {!isCollapsed && (
              <div className="ml-2 flex flex-col">
                <span className="text-[10px] font-mono leading-none text-slate-300 uppercase">ClickHouse</span>
                <span className="text-[9px] text-green-500">RUNNING</span>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;
